<?php
namespace App\Domain\Hunts;use App\Domain\Combat\CombatLimits;use App\Domain\Hunts\Exceptions\NoActiveEncounterSizeException;use App\Domain\Random\RandomNumberGenerator;use InvalidArgumentException;
final class EncounterSizeSelector{private $rng;public function __construct(RandomNumberGenerator $rng){$this->rng=$rng;}public function select($configs){$valid=[];$seen=[];$total=0;foreach($configs as $config){$active=is_array($config)?($config['is_active']??false):$config->is_active;if(!$active)continue;$count=(int)(is_array($config)?$config['enemy_count']:$config->enemy_count);$weight=(int)(is_array($config)?$config['weight']:$config->weight);if($count<1||$count>CombatLimits::MAX_PARTICIPANTS_PER_SIDE||$weight<=0||isset($seen[$count])||$weight>PHP_INT_MAX-$total)throw new InvalidArgumentException('Invalid encounter size configuration.');$seen[$count]=true;$total+=$weight;$valid[]=[$count,$weight];}if(!$valid)throw new NoActiveEncounterSizeException('No active encounter size configuration.');$roll=$this->rng->randomInt(1,$total);$sum=0;foreach($valid as $row){$sum+=$row[1];if($roll<=$sum)return$row[0];}throw new InvalidArgumentException('Invalid weighted selection.');}}
